<script setup>
import { reactive, ref } from 'vue';import { Head,Link } from '@inertiajs/vue3';import axios from 'axios';import AppLayout from '@/Layouts/AppLayout.vue';
const props=defineProps({projekt:Object,definitions:Array});const groups=ref(JSON.parse(JSON.stringify(props.definitions||[])));const empty=()=>({key:'',title:'',purpose:'',content:'',required:false,allow_withdrawal:true,active:true,sort_order:0});const form=reactive(empty());const saving=ref(false);const create=async()=>{saving.value=true;try{const r=await axios.post(route('projekt.consents.store',props.projekt.id),form);groups.value.push({current:r.data.definition,versions:[r.data.definition]});Object.assign(form,empty());}finally{saving.value=false;}};const publish=async(group)=>{const r=await axios.post(route('projekt.consents.revise',group.current.id),group.current);group.versions.unshift(r.data.definition);group.current=r.data.definition;};const toggle=async(group)=>{const r=await axios.put(route('projekt.consents.active',group.current.id),{active:!group.current.active});group.current.active=r.data.definition.active;group.versions[0].active=r.data.definition.active;};
</script>
<template><AppLayout><Head title="Einwilligungen verwalten"/><div class="mx-auto max-w-6xl space-y-6 p-6"><header class="flex justify-between"><div><p class="text-sm text-gray-500">{{ projekt.name }}</p><h1 class="text-2xl font-bold">Einwilligungen und Freigaben</h1></div><Link :href="route('projekt.show',projekt.id)" class="rounded border px-4 py-2">Zurück zum Projekt</Link></header><section class="rounded-xl border bg-white p-6"><h2 class="font-semibold">Neue Einwilligung</h2><div class="mt-4 grid gap-3 md:grid-cols-2"><input v-model="form.key" placeholder="Schlüssel, z. B. foto_freigabe" class="rounded border-gray-300"/><input v-model="form.title" placeholder="Titel" class="rounded border-gray-300"/><textarea v-model="form.purpose" placeholder="Zweck der Verarbeitung" class="rounded border-gray-300 md:col-span-2"></textarea><textarea v-model="form.content" rows="6" placeholder="Vollständiger Einwilligungstext" class="rounded border-gray-300 md:col-span-2"></textarea><label><input v-model="form.required" type="checkbox"/> Pflichtnachweis</label><label><input v-model="form.allow_withdrawal" type="checkbox"/> Widerruf im Portal erlauben</label></div><button class="mt-4 rounded bg-zbb px-4 py-2 text-white" :disabled="saving" @click="create">Anlegen</button></section><section v-for="group in groups" :key="group.current.key" class="rounded-xl border bg-white p-6"><div class="flex justify-between"><div><h2 class="font-semibold">{{ group.current.title }} <span class="text-xs text-gray-500">v{{ group.current.version }}</span></h2><p class="text-sm text-gray-500">{{ group.current.key }}</p></div><button class="text-sm" :class="group.current.active?'text-red-600':'text-green-600'" @click="toggle(group)">{{ group.current.active?'Deaktivieren':'Aktivieren' }}</button></div><div class="mt-4 grid gap-3 md:grid-cols-2"><input v-model="group.current.title" class="rounded border-gray-300"/><textarea v-model="group.current.purpose" class="rounded border-gray-300"></textarea><textarea v-model="group.current.content" rows="6" class="rounded border-gray-300 md:col-span-2"></textarea><label><input v-model="group.current.required" type="checkbox"/> Pflichtnachweis</label><label><input v-model="group.current.allow_withdrawal" type="checkbox"/> Widerruf erlauben</label></div><button class="mt-4 rounded bg-blue-600 px-4 py-2 text-white" @click="publish(group)">Als neue Version veröffentlichen</button><p class="mt-3 text-xs text-gray-500">{{ group.versions.length }} Version(en); ältere Nachweise bleiben unverändert erhalten.</p></section></div></AppLayout></template>
